// REPORT-005 — Code_FormatMetrics — VERSION FINALE
const data = $input.first().json;
const ts   = new Date();

const MTTD         = parseFloat(data.avg_mttd_minutes  || 0);
const MTTR         = parseFloat(data.avg_mttr_minutes  || 0);
const total        = parseInt(data.total_incidents     || 0);
const open_count   = parseInt(data.open_incidents      || 0);
const closed_count = parseInt(data.closed_incidents    || 0);
const p0_count     = parseInt(data.p0_count            || 0);
const p1_count     = parseInt(data.p1_count            || 0);
const p2_count     = parseInt(data.p2_count            || 0);
const auto_count   = parseInt(data.auto_resolved       || 0);
const human_count  = parseInt(data.human_escalated     || 0);
const sla_breached = parseInt(data.sla_breached_count  || 0);

const sla_ok_pct = total > 0 ? Math.round(((total - sla_breached) / total) * 100) : 100;
const auto_rate  = total > 0 ? Math.round((auto_count / total) * 100) : 0;

const MITRE_BY_TYPE = {
  'brute_force'    : 'T1110 — Brute Force',
  'phishing'       : 'T1566 — Phishing',
  'data_exfil'     : 'T1041 — Exfiltration Over C2',
  'port_scan'      : 'T1046 — Network Service Discovery',
  'priv_escalation': 'T1068 — Exploitation for Privilege Escalation'
};
const topMitre = data.top_mitre_tech || MITRE_BY_TYPE[data.top_attack_type] || 'T1110 — Brute Force';

let maturityLevel = 'INDÉTERMINÉ';
if (MTTR > 0) {
  if (MTTR < 15)      maturityLevel = 'ELITE (< 15 min MTTR)';
  else if (MTTR < 30) maturityLevel = 'MATURE (< 30 min MTTR)';
  else if (MTTR < 60) maturityLevel = 'EN PROGRESSION (< 60 min MTTR)';
  else                maturityLevel = 'INITIAL (> 60 min MTTR)';
}

// ── SECURITY POSTURE (ajout final) ────────────────────────
let security_posture = 'GREEN';
let posture_reason   = 'Aucune anomalie détectée';
if (p0_count > 0) {
  security_posture = 'RED';
  posture_reason   = p0_count + ' incident(s) P0 actif(s)';
} else if (sla_ok_pct < 80 || MTTR > 60 || open_count > 10) {
  security_posture = 'AMBER';
  posture_reason   = 'SLA compliance: ' + sla_ok_pct + '% | MTTR: ' + MTTR + 'min | Open: ' + open_count;
} else if (p1_count > 3) {
  security_posture = 'AMBER';
  posture_reason   = p1_count + ' incidents P1 en cours';
}

// ── RECOMMANDATION ─────────────────────────────────────────
let recommendation = 'Données insuffisantes — lancer une simulation';
if (total > 0) {
  if (p0_count > 0)         recommendation = 'CRITIQUE: ' + p0_count + ' incident(s) P0 actif(s) — intervention immédiate';
  else if (MTTD > 10)       recommendation = 'MTTD élevé (' + MTTD + ' min) — affiner les règles de corrélation AFD';
  else if (MTTR > 60)       recommendation = 'MTTR élevé (' + MTTR + ' min) — automatiser davantage la réponse L1';
  else if (auto_rate < 50)  recommendation = 'Taux automation faible (' + auto_rate + '%) — revoir les playbooks SOAR';
  else if (sla_ok_pct < 80) recommendation = 'SLA compliance faible (' + sla_ok_pct + '%) — réviser les seuils SLA';
  else                      recommendation = 'Performance nominale — maintenir les seuils SLA actuels';
}

return [{ json: {
  report_generated : ts.toISOString(),
  report_period    : 'Dernières 24h',
  soc_tier         : 'SOC L1 Automatisé — ENSAM Casablanca',
  data_source      : 'Supabase PostgreSQL — vw_soc_dashboard',
  security_posture,
  posture_reason,
  MTTD_minutes     : MTTD,
  MTTR_minutes     : MTTR,
  incidents_total  : total,
  incidents_open   : open_count,
  incidents_closed : closed_count,
  incidents_p0     : p0_count,
  incidents_p1     : p1_count,
  incidents_p2     : p2_count,
  auto_resolved    : auto_count,
  human_escalated  : human_count,
  automation_rate  : auto_rate + '%',
  sla_compliance   : sla_ok_pct + '%',
  sla_breached     : sla_breached,
  top_source_ip    : data.top_source_ip   || 'N/A',
  top_attack_type  : data.top_attack_type || 'N/A',
  top_mitre_tech   : topMitre,
  maturity_level   : maturityLevel,
  recommendation
}}];

// REPORT-005 — Code_AuthToken — VERSION CORRIGÉE CLOUD
const raw = $input.first().json;
const ts  = new Date().toISOString();

const receivedToken = String(
  (raw.headers && raw.headers['x-soc-token']) ||
  (raw.headers && raw.headers['X-Soc-Token']) ||
  raw['x-soc-token'] ||
  raw.soc_token      ||
  (raw.body && raw.body['x-soc-token']) ||
  (raw.body && raw.body.soc_token) || ''
).trim();

const SOC_TOKEN = String($vars.REPORT_TOKEN || '').trim();

if (!receivedToken) {
  return [{ json: { error: 'UNAUTHORIZED',
    message: 'Token manquant', _auth_failed: true, timestamp: ts } }];
}
if (!SOC_TOKEN) {
  return [{ json: { error: 'MISCONFIGURATION',
    message: 'REPORT_TOKEN non configuré', _auth_failed: true, timestamp: ts } }];
}
if (receivedToken !== SOC_TOKEN) {
  console.log('[SECURITY][REPORT-005] Token invalide — ' + ts);
  return [{ json: { error: 'UNAUTHORIZED',
    message: 'Token invalide', _auth_failed: true, timestamp: ts } }];
}

return [{ json: { _auth_ok: true, timestamp: ts } }];
